// The ~21 base badge glyphs (asset-manifest §5) + the celebration medal (§6).
// Monochrome line/solid SVGs drawn in `currentColor`, so the tile recolors them by
// state with one rule (lit → --accent, locked → --locked) — the same recolor trick as
// the cans. The 79 §5.11 badges all map onto these via the `glyph` column in defs.ts.
// M6 added the distinctive emblems from the PRD Glyph column (crown / loop / "3" /
// all-lines ring) as `GlyphMod` overlays (MODS below); the numeric "+tier" pips on the
// long ladders are intentionally not drawn (deferred-decisions.md — no mockup/spec).
//
// Glyph coordinate space is 64×64 (the hand-authored art in Updated-stuff/ is drawn at
// 64×64). 18 base glyphs were replaced with that art. Three legacy glyphs (cans-pile,
// star-broken, medal) plus the MODS overlays and the modded-base inset are still authored
// in the old 24-space and are rendered scaled by ≈2.6667 (= 64/24) to fill the box.

import type { JSX } from 'preact';
import type { GlyphId, GlyphMod } from './defs';

/** A small soda-can shape (24-space). Still used by the kept `cans-pile` glyph. */
function can(x: number, y: number, w: number, h: number): JSX.Element {
  const r = Math.min(w, h) * 0.18;
  return (
    <g>
      <rect x={x} y={y} width={w} height={h} rx={r} />
      <path d={`M${x} ${y + h * 0.22} h${w}`} />
      <path d={`M${x} ${y + h * 0.78} h${w}`} />
    </g>
  );
}

